class Solution:
    def sortVowels(self, s: str) -> str:
        vowels = {'a', 'e', 'i', 'o', 'u', 'A', 'E', 'I', 'O', 'U'}
        vowel_indices = []
        vowels_list = []

        for i, char in enumerate(s):
            if char in vowels:
                vowel_indices.append(i)
                vowels_list.append(char)

        vowels_list.sort(key=lambda x: ord(x))
        result = list(s)

        for idx, vowel in zip(vowel_indices, vowels_list):
            result[idx] = vowel

        return ''.join(result)
